const BASS = [
  [130,0.3],[0,0.15],[196,0.3],[0,0.15],
  [130,0.3],[0,0.15],[174,0.3],[0,0.15],
  [130,0.3],[0,0.15],[196,0.3],[0,0.15],
  [116,0.3],[0,0.15],[174,0.3],[0,0.15],
];

function startBGM() {
  if (bgmPlaying) return;
  audioCtx = new (window.AudioContext || window.webkitAudioContext)();
  bgmPlaying = true;
  playMelodyLoop();
}

function stopBGM() {
  bgmPlaying = false;
  if (audioCtx) { audioCtx.close(); audioCtx = null; }
}

function playNote(freq, start, duration, type='square', vol=0.08, detune=0) {
  if (!audioCtx || !bgmPlaying || freq === 0) return;
  const osc = audioCtx.createOscillator();
  const gain = audioCtx.createGain();
  osc.connect(gain);
  gain.connect(audioCtx.destination);
  osc.type = type;
  osc.frequency.value = freq;
  osc.detune.value = detune;
  gain.gain.setValueAtTime(vol, start);
  gain.gain.linearRampToValueAtTime(0, start + duration * 0.9);
  osc.start(start);
  osc.stop(start + duration);
}

function playMelodyLoop() {
  if (!bgmPlaying || !audioCtx) return;
  const now = audioCtx.currentTime;
  let t = now;
  const loopDuration = MELODY.reduce((s, n) => s + n[1], 0);
  MELODY.forEach(([freq, dur]) => { playNote(freq, t, dur, 'square', 0.07); t += dur; });
  let bt = now;
  const bassLoop = Math.ceil(loopDuration / BASS.reduce((s,n)=>s+n[1],0));
  for (let b = 0; b < bassLoop; b++) {
    BASS.forEach(([freq, dur]) => { playNote(freq, bt, dur, 'triangle', 0.05); bt += dur; });
  }
  for (let p = 0; p < loopDuration; p += 0.6) {
    playNote(100, now + p, 0.05, 'sawtooth', 0.04);
  }
  setTimeout(playMelodyLoop, loopDuration * 1000 - 100);
}

