const SPEED    = 3.8;

// Player bounding box: w=52, h=44
// Visual poodle sits so that its feet (bottom of legs at y+44) land on platform
const PLAYER_W = 52;
const PLAYER_H = 44;

let player = {
  x: 80, y: GROUND_Y - PLAYER_H,
  w: PLAYER_W, h: PLAYER_H,
  vx: 0, vy: 0,
  onGround: false,
  jumpsLeft: 2,
  facing: 1,
  state: 'idle',
};

function resetPlayer(checkpointIdx) {
  const cpX = checkpoints[checkpointIdx] + 80;
  player.x  = cpX;
  player.y  = GROUND_Y - PLAYER_H;
  player.vx = 0; player.vy = 0;
  player.onGround = false;
  player.jumpsLeft = 2;
  camera.x = Math.max(0, cpX - W / 3);
}

function handleJump() {
  if (player.jumpsLeft > 0) {
    player.vy = JUMP_POW;
    player.jumpsLeft--;
    player.onGround = false;
  }
}

