// ── DRAW HELPERS ─────────────────────────────────────────────
function pr(x, y, w, h, color) {
  ctx.fillStyle = color;
  ctx.fillRect(Math.round(x), Math.round(y), w, h);
}

// ─────────────────────────────────────────────────────────────
//  POODLE SIDE-VIEW
//  Tamaño: 52 ancho x 44 alto
//  Las patas llegan hasta y=44 (el fondo del bounding box)
// ─────────────────────────────────────────────────────────────
function drawPoodle(wx, wy, facing, state, frame, scale=1) {
  ctx.save();
  const pivotX = wx + 26 * scale;
  ctx.translate(pivotX, wy);
  if (facing < 0) ctx.scale(-1, 1);
  ctx.translate(-26 * scale, 0);
  ctx.scale(scale, scale);

  const f = Math.floor(frame / 7) % 4;
  const isRun   = state === 'run';
  const isJump  = state === 'jump' || state === 'fall';

  const legAngles = isRun ? [14, 4, -14, -4] : [0, 0, 0, 0];
  const la = isJump ? -18 : legAngles[f];

  // ── TAIL ─────────────────────────────────────────────────
  const tailWag = isJump ? 0 : Math.sin(frame * 0.22) * 18;
  ctx.save();
  ctx.translate(4, 14);
  ctx.rotate((-30 + tailWag) * Math.PI / 180);
  pr(0, -14, 4, 14, '#d8d8d8');
  pr(-4, -22, 12, 12, '#f0f0f0');
  pr(-3, -24, 10,  8, '#ffffff');
  pr(-2, -20,  8,  6, '#e8e8e8');
  ctx.restore();

  // ── BODY ─────────────────────────────────────────────────
  // Body sits from y=10 to y=28
  pr(10, 10, 34, 18, '#f5f5f5');
  pr( 8, 12, 38, 14, '#ffffff');
  pr(10,  9, 32, 20, '#f8f8f8');
  pr(12,  8,  8,  5, '#ebebeb');
  pr(24,  8,  8,  5, '#ebebeb');
  pr(36, 10,  6,  5, '#ebebeb');
  pr(14, 26,  8,  4, '#ebebeb');
  pr(28, 26,  6,  4, '#ebebeb');

  // ── PATAS TRASERAS ────────────────────────────────────────
  // Pata trasera lejana — starts at y=26, goes to y=44
  ctx.save();
  ctx.translate(16, 26);
  ctx.rotate((-la * 0.7) * Math.PI / 180);
  pr(-3, 0, 7, 10, '#e0e0e0');
  pr(-2, 9, 6,  8, '#d8d8d8');
  pr(-4,16,10,  2, '#e8e8e8');  // pezuña fina
  pr(-4, 7, 8,  6, '#eeeeee');  // pompom rodilla
  ctx.restore();

  // Pata trasera cercana
  ctx.save();
  ctx.translate(20, 26);
  ctx.rotate((la * 0.7) * Math.PI / 180);
  pr(-3, 0, 7, 10, '#ececec');
  pr(-2, 9, 6,  8, '#e4e4e4');
  pr(-4,16,10,  2, '#f0f0f0');
  pr(-4, 7, 8,  6, '#f2f2f2');
  ctx.restore();

  // ── PATAS DELANTERAS ─────────────────────────────────────
  // Starts at y=24, goes to y=44
  ctx.save();
  ctx.translate(37, 24);
  ctx.rotate((la * 0.8) * Math.PI / 180);
  pr(-3, 0, 7, 10, '#e0e0e0');
  pr(-2, 9, 6,  8, '#d8d8d8');
  pr(-4,16,10,  2, '#e8e8e8');
  pr(-4, 7, 8,  6, '#eeeeee');
  ctx.restore();

  // Delantera cercana
  ctx.save();
  ctx.translate(41, 24);
  ctx.rotate((-la * 0.8) * Math.PI / 180);
  pr(-3, 0, 7, 10, '#ececec');
  pr(-2, 9, 6,  8, '#e4e4e4');
  pr(-4,16,10,  2, '#f0f0f0');
  pr(-4, 7, 8,  6, '#f2f2f2');
  ctx.restore();

  // ── CUELLO ───────────────────────────────────────────────
  pr(38,  4, 10, 14, '#f0f0f0');
  pr(37,  3, 12, 10, '#f5f5f5');

  // ── CABEZA ───────────────────────────────────────────────
  pr(42, -6, 20, 20, '#ffffff');
  pr(40, -4, 24, 16, '#f8f8f8');
  pr(42, -5, 20, 18, '#ffffff');
  pr(44,-10, 14,  8, '#f0f0f0');
  pr(46,-12, 10,  6, '#ffffff');
  pr(48,-13,  8,  5, '#ebebeb');
  pr(40,  2,  6,  8, '#f0f0f0');

  // ── OREJA ────────────────────────────────────────────────
  pr(46,  0,  7, 18, '#e8e8e8');
  pr(45,  2,  6, 16, '#f0f0f0');
  pr(44, 16,  8,  6, '#e8e8e8');

  // ── OJO ──────────────────────────────────────────────────
  pr(55, -1,  5,  5, '#1a1a1a');
  pr(56, -1,  2,  2, '#ffffff');

  // ── NARIZ ────────────────────────────────────────────────
  pr(60,  7,  5,  4, '#1a1a1a');
  pr(61,  8,  3,  2, '#333');

  // ── HOCICO ───────────────────────────────────────────────
  pr(56,  6,  8,  8, '#f2efed');
  pr(57, 11,  5,  2, '#ddd');
  pr(58, 12,  2,  2, '#888');
  pr(60, 13,  2,  2, '#888');

  ctx.restore();
}

// ── POODLE HUG POSE ──────────────────────────────────────────
function drawPoodleHug(x, y, frame) {
  ctx.save();
  ctx.translate(x, y);

  const wag = Math.sin(frame * 0.38) * 20;

  ctx.save();
  ctx.translate(4, 14);
  ctx.rotate((-30 + wag) * Math.PI / 180);
  pr(0, -14, 4, 14, '#d8d8d8');
  pr(-4,-22,12,12,'#f0f0f0');
  pr(-3,-24,10, 8,'#ffffff');
  ctx.restore();

  pr(10,10,34,18,'#f5f5f5');
  pr( 8,12,38,14,'#ffffff');

  // back legs grounded
  pr(13,26,7,12,'#e0e0e0');
  pr(12,36,10,2,'#e8e8e8');
  pr(18,26,7,12,'#ececec');
  pr(17,36,10,2,'#f0f0f0');

  // front legs raised (abrazo)
  pr(38, 2, 7,14,'#e0e0e0');
  pr(37,-2,10, 7,'#e8e8e8');
  pr(42, 2, 7,14,'#ececec');
  pr(41,-2,10, 7,'#f0f0f0');

  pr(38, 4,10,12,'#f0f0f0');
  pr(42,-6,20,20,'#ffffff');
  pr(40,-4,24,16,'#f8f8f8');
  pr(44,-10,14, 8,'#f0f0f0');
  pr(46,-12,10, 6,'#ffffff');
  pr(46, 0, 7,18,'#e8e8e8');
  pr(45, 2, 6,16,'#f0f0f0');
  pr(44,16, 8, 6,'#e8e8e8');

  ctx.fillStyle='#1a1a1a';
  ctx.beginPath(); ctx.arc(58,2,3,Math.PI,0); ctx.fill();

  pr(60, 7, 5, 4,'#1a1a1a');
  pr(56, 6, 8, 8,'#f2efed');

  pr(58,12,6,5,'#e07070');
  pr(59,15,4,3,'#c05050');

  ctx.restore();
}

// ── DRAW GIRL ─────────────────────────────────────────────────
